def compute_score() -> tuple[str, float]:
    # Check PPTDiff for changes outside slide 4
    slide_nums_to_ids = {s.slide_number: s.slide_id for s in ppt_diff.added_slides + ppt_diff.removed_slides}
    # Check added/removed/modified slides
    changes = []
    for s in ppt_diff.added_slides + ppt_diff.removed_slides:
        if s.slide_number != 4:
            changes.append(f"Slide {s.slide_number} was added/removed.")
    for orig, mod in ppt_diff.modified_slides:
        if orig.slide_number != 4:
            changes.append(f"Slide {orig.slide_number} was modified.")
    # Check animations/transitions
    for a in ppt_diff.added_animations + ppt_diff.removed_animations:
        if a.slide_id and a.slide_id != ppt_diff.modified_slides[0][1].slide_id:
            changes.append(f"Animation changed on slide {a.slide_id}.")
    for t in ppt_diff.added_transitions + ppt_diff.removed_transitions:
        if t.slide_id and t.slide_id != ppt_diff.modified_slides[0][1].slide_id:
            changes.append(f"Transition changed on slide {t.slide_id}.")
    if changes:
        return "Extraneous changes to other slides detected: " + "; ".join(changes), 0.0
    return "No extraneous changes to other slides.", 1.0

def compute_score() -> tuple[str, float]:
    """Verify that nothing except the image(s) changed on slide 4.

    Criteria for passing (score=1):
      - All non-image shapes present in the original are present in the modified.
      - No non-image shape changed its geometry (left/top/width/height beyond tiny tolerance).
      - No non-image shape changed its text content.
      - We ignore any changes to picture shapes (size/position) because image modification is allowed.

    Otherwise score=0 with an explanatory message.
    """
    from pptx import Presentation
    from pptx.enum.shapes import MSO_SHAPE_TYPE

    # Expect global variables injected by framework
    try:
        orig_path = original_ppt_path  # type: ignore[name-defined]
        mod_path = modified_ppt_path  # type: ignore[name-defined]
    except NameError:
        return "Internal error: required global paths not provided.", 0.0

    try:
        prs_orig = Presentation(orig_path)
        prs_mod = Presentation(mod_path)
    except Exception:
        return "Failed to open one of the PPT files.", 0.0

    # Slide 4 index = 3
    try:
        slide_orig = prs_orig.slides[3]
        slide_mod = prs_mod.slides[3]
    except IndexError:
        return "Slide 4 not found in one of the presentations.", 0.0

    def is_picture(sh):
        try:
            if sh.shape_type == MSO_SHAPE_TYPE.PICTURE:
                return True
            if sh.shape_type == MSO_SHAPE_TYPE.PLACEHOLDER and hasattr(sh, "image"):
                return True
            if hasattr(sh, "image"):
                return True
        except Exception:
            return False
        return False

    # Collect non-image shapes
    orig_non_imgs = [sh for sh in slide_orig.shapes if not is_picture(sh)]
    mod_non_imgs = [sh for sh in slide_mod.shapes if not is_picture(sh)]

    # Quick cardinality check
    if len(orig_non_imgs) != len(mod_non_imgs):
        return "Non-image elements on slide 4 were added or removed.", 0.0

    # Build a multiset of descriptors for robust matching (order can differ)
    def shape_descriptor(sh):
        # Some shapes may lack certain attrs; use getattr with default
        left = getattr(sh, "left", None)
        top = getattr(sh, "top", None)
        width = getattr(sh, "width", None)
        height = getattr(sh, "height", None)
        # Normalize text (strip whitespace); if no text attribute use None
        text = getattr(sh, "text", None)
        if isinstance(text, str):
            text = " ".join(text.split())  # collapse whitespace
        stype = getattr(sh, "shape_type", None)
        return {
            "shape_type": stype,
            "left": left,
            "top": top,
            "width": width,
            "height": height,
            "text": text,
        }

    orig_descs = [shape_descriptor(sh) for sh in orig_non_imgs]
    mod_descs = [shape_descriptor(sh) for sh in mod_non_imgs]

    # Because EMU values can have tiny differences, allow small tolerance.
    POS_TOL = 1000  # ~0.001 inch (approx); adjust as needed
    SIZE_TOL = 1000

    def close(a, b, tol):
        if a is None or b is None:
            return a == b
        try:
            return abs(int(a) - int(b)) <= tol
        except Exception:
            return a == b

    # Attempt to match each original descriptor with exactly one modified descriptor.
    used = [False] * len(mod_descs)
    for o in orig_descs:
        match_i = -1
        for i, m in enumerate(mod_descs):
            if used[i]:
                continue
            if o["shape_type"] != m["shape_type"]:
                continue
            if not close(o["left"], m["left"], POS_TOL):
                continue
            if not close(o["top"], m["top"], POS_TOL):
                continue
            if not close(o["width"], m["width"], SIZE_TOL):
                continue
            if not close(o["height"], m["height"], SIZE_TOL):
                continue
            if o["text"] != m["text"]:
                continue
            match_i = i
            break
        if match_i == -1:
            return "A non-image element was changed (geometry or text).", 0.0
        used[match_i] = True

    # All non-image shapes matched unchanged -> pass
    return "Only image changes detected; no extraneous modifications to other elements on slide 4.", 1.0
